import Vue from "vue";
import Router from "vue-router";
import Home from "./views/Home.vue";
import About from "./views/About.vue";
import Famcorp from "./views/Famcorp.vue";
import Musicality from "./views/Musicality.vue";

Vue.use(Router);

export default new Router({
    routes: [{
            path: "/",
            name: "home",
            component: Home
        },
        {
            path: "/about",
            name: "about",
            component: About
        },
        {
            path: "/famcorp",
            name: "famcorp",
            component: Famcorp
        },
        {
            path: "/musicality",
            name: "musicality",
            component: Musicality
        }
    ]
});